33	export interface OpenAIProvider extends ProviderV3 {
34	  (modelId: OpenAIResponsesModelId): LanguageModelV3;
35	
36	  /**
37	   * Creates an OpenAI model for text generation.
38	   */
39	  languageModel(modelId: OpenAIResponsesModelId): LanguageModelV3;
40	
41	  /**
42	   * Creates an OpenAI chat model for text generation.
43	   */
44	  chat(modelId: OpenAIChatModelId): LanguageModelV3;
45	
46	  /**
47	   * Creates an OpenAI responses API model for text generation.
48	   */
49	  responses(modelId: OpenAIResponsesModelId): LanguageModelV3;
50	
51	  /**
52	   * Creates an OpenAI completion model for text generation.
53	   */
54	  completion(modelId: OpenAICompletionModelId): LanguageModelV3;
55	
56	  /**
57	   * Creates a model for text embeddings.
58	   */
59	  embedding(modelId: OpenAIEmbeddingModelId): EmbeddingModelV3;
60	
61	  /**
62	   * Creates a model for text embeddings.
63	   */
64	  embeddingModel(modelId: OpenAIEmbeddingModelId): EmbeddingModelV3;
65	
66	  /**
67	   * @deprecated Use `embedding` instead.
68	   */
69	  textEmbedding(modelId: OpenAIEmbeddingModelId): EmbeddingModelV3;
70	
71	  /**
72	   * @deprecated Use `embeddingModel` instead.
73	   */
74	  textEmbeddingModel(modelId: OpenAIEmbeddingModelId): EmbeddingModelV3;
75	
76	  /**
77	   * Creates a model for image generation.
78	   */
79	  image(modelId: OpenAIImageModelId): ImageModelV3;
80	
81	  /**
82	   * Creates a model for image generation.
83	   */
84	  imageModel(modelId: OpenAIImageModelId): ImageModelV3;
